mapper.select:
SELECT commentid AS commentId, boardid AS boardId, userid AS userId, username AS userName, content, parentid AS parentId, hidden, createdat AS createdAt, updatedat AS updatedAt FROM freeboard_comment WHERE boardid = #{boardId}
AND hidden = 0
ORDER BY createdat ASC

